"use client"

import * as React from "react"
import {
  ActionQueue,
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  PersonCell,
  ScheduleGrid,
  Separator,
  StatGroup,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  type ActionItem,
  type ScheduleCell,
  type ScheduleCellTone,
} from "@gunjo/ui"
import {
  IconChevronRight,
  IconClockPause,
  IconUserCheck,
} from "@tabler/icons-react"

import {
  ABSENCES,
  ALERTS,
  CREW,
  CREW_BY_ID,
  DEPOT,
  DUTIES,
  DUTY_BY_NO,
  DUTY_STATUS_LABEL,
  ON_DUTY_AT,
  OPS_DATE,
  SPARE_CREW,
  type Duty,
} from "./data"
import { DutyDetail } from "./DutyDetail"
import { STATUS_BADGE, fmtMinutes } from "./helpers"

const MANAGER_ID = "助役 大西 透"

// 交番表（crew × 時間帯）の列定義
const TIME_BANDS = [
  { id: "early", label: "早朝", sublabel: "〜07:00" },
  { id: "am", label: "午前", sublabel: "07–10" },
  { id: "mid", label: "日中", sublabel: "10–13" },
  { id: "pm", label: "午後", sublabel: "13–17" },
  { id: "eve", label: "夕方", sublabel: "17–22" },
]

function hm(t?: string): number | null {
  if (!t) return null
  const [h, m] = t.split(":").map(Number)
  return h * 60 + m
}

const BAND_RANGES: Record<string, [number, number]> = {
  early: [0, 7 * 60],
  am: [7 * 60, 10 * 60],
  mid: [10 * 60, 13 * 60],
  pm: [13 * 60, 17 * 60],
  eve: [17 * 60, 22 * 60],
}

const STATUS_TONE: Record<string, ScheduleCellTone> = {
  before: "muted",
  "roll-called": "info",
  "on-board": "success",
  rest: "muted",
  "turn-back": "warning",
  done: "default",
  "roll-call-pending": "destructive",
}

export default function RailCrewRosterPage() {
  const [selected, setSelected] = React.useState<Duty | null>(null)
  const [open, setOpen] = React.useState(false)

  const openDuty = React.useCallback((duty: Duty) => {
    setSelected(duty)
    setOpen(true)
  }, [])

  // KPI
  const onBoard = DUTIES.filter((d) => d.status === "on-board").length
  const pending = DUTIES.filter((d) => d.status === "roll-call-pending").length
  const overRisk = DUTIES.filter(
    (d) =>
      d.continuousMinutes >
      (CREW_BY_ID[d.crewId]?.continuousLimitMin ?? Infinity),
  ).length
  const unassigned = DUTIES.filter((d) => !d.crewId).length

  // 交番グリッドのセル：crew 行 × 時間帯 列。仕業が走る時間帯に状態を描く。
  const cells: ScheduleCell[] = []
  for (const crew of CREW) {
    const duty = DUTIES.find((d) => d.crewId === crew.id)
    if (!duty) continue
    const on = hm(duty.signOn) ?? 0
    const off = hm(duty.signOff) ?? 24 * 60
    for (const band of TIME_BANDS) {
      const [bs, be] = BAND_RANGES[band.id]
      const overlaps = on < be && off > bs
      if (!overlaps) continue
      // この時間帯に通過する列車番号を拾う
      const trainsInBand = duty.legs
        .filter((l) => {
          const ld = hm(l.actualDep ?? l.plannedDep)
          return l.trainNo && ld != null && ld >= bs && ld < be
        })
        .map((l) => l.trainNo as string)
      cells.push({
        rowId: crew.id,
        colId: band.id,
        tone: STATUS_TONE[duty.status],
        content: (
          <div className="flex flex-col gap-0.5 text-left">
            <span className="text-[11px] font-semibold">{duty.no}</span>
            <span className="text-[10px] text-muted-foreground">
              {trainsInBand.length ? trainsInBand.join(" / ") : duty.route}
            </span>
          </div>
        ),
        description: `${duty.no}、${DUTY_STATUS_LABEL[duty.status]}${
          trainsInBand.length ? `、担当 ${trainsInBand.join("・")}` : ""
        }`,
        onSelect: () => openDuty(duty),
      })
    }
  }

  // 要対応アラート → ActionQueue
  const alertItems: ActionItem[] = ALERTS.map((a) => {
    const duty = a.dutyNo ? DUTY_BY_NO[a.dutyNo] : undefined
    return {
      id: a.id,
      severity: a.severity,
      kind: a.kind,
      title: a.title,
      detail: a.detail,
      meta: a.meta,
      onSelect: duty ? () => openDuty(duty) : undefined,
      actions: duty ? (
        <Button
          size="xs"
          variant="outline"
          onClick={(e) => {
            e.stopPropagation()
            openDuty(duty)
          }}
        >
          仕業を開く
        </Button>
      ) : undefined,
    }
  })

  return (
    <main className="mx-auto w-full max-w-6xl px-4 py-6 sm:px-6">
      {/* タイトル */}
      <header className="mb-5">
        <p className="text-xs font-medium text-muted-foreground">
          乗務員 仕業・行路管理（交番）
        </p>
        <div className="flex flex-wrap items-end justify-between gap-2">
          <h1 className="text-2xl font-bold tracking-tight">
            {DEPOT}・本日の運用
          </h1>
          <p className="text-sm text-muted-foreground tabular-nums">
            {OPS_DATE}　{ON_DUTY_AT}
          </p>
        </div>
      </header>

      {/* KPI ストリップ */}
      <StatGroup
        className="mb-6"
        cols={{ base: 2, md: 3, lg: 6 }}
        items={[
          { label: "本日の仕業数", value: DUTIES.length, hint: "交番 全行路" },
          {
            label: "乗務中",
            value: onBoard,
            tone: "positive",
            hint: "在線中",
          },
          {
            label: "点呼未了",
            value: pending,
            tone: pending ? "negative" : "neutral",
            hint: "要 出勤点呼",
          },
          {
            label: "超過の恐れ",
            value: overRisk,
            tone: overRisk ? "negative" : "neutral",
            hint: "連続乗務 超過",
          },
          { label: "予備（待機）", value: SPARE_CREW.length, hint: "充当可" },
          {
            label: "年休・病欠",
            value: ABSENCES.length,
            hint: "本日 欠務",
          },
        ]}
      />

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-[1fr_360px]">
        {/* 左：交番・仕業 */}
        <div className="min-w-0 space-y-6">
          <Tabs defaultValue="koban" className="border-0">
            <TabsList>
              <TabsTrigger value="koban">交番表（乗務員 × 時間帯）</TabsTrigger>
              <TabsTrigger value="duties">仕業一覧</TabsTrigger>
            </TabsList>

            {/* 交番表 */}
            <TabsContent value="koban" className="p-0 pt-3">
              <Card>
                <CardHeader className="p-4 pb-2">
                  <CardTitle as="h2" className="text-base">
                    交番表
                  </CardTitle>
                  <p className="text-xs text-muted-foreground">
                    セルを選択で仕業の行路・点呼・勤務時間を表示。状態は色＋ラベルで識別。
                  </p>
                </CardHeader>
                <CardContent className="p-3 pt-0">
                  <ScheduleGrid
                    label="本日の交番（乗務員 × 時間帯）"
                    cornerLabel="乗務員"
                    rowHeaderWidth={132}
                    minColumnWidth={108}
                    rows={CREW.map((c) => ({
                      id: c.id,
                      label: (
                        <span className="flex flex-col text-left leading-tight">
                          <span className="text-xs font-semibold">
                            {c.name}
                          </span>
                          <span className="text-[10px] text-muted-foreground">
                            {c.id}・{c.role === "driver" ? "運転士" : "車掌"}
                          </span>
                        </span>
                      ),
                      ariaLabel: `${c.name} ${c.id}`,
                    }))}
                    columns={TIME_BANDS}
                    cells={cells}
                  />
                </CardContent>
              </Card>
            </TabsContent>

            {/* 仕業一覧 */}
            <TabsContent value="duties" className="p-0 pt-3">
              <ul className="space-y-2" role="list">
                {DUTIES.map((duty) => {
                  const crew = CREW_BY_ID[duty.crewId]
                  return (
                    <li key={duty.no}>
                      <button
                        type="button"
                        onClick={() => openDuty(duty)}
                        className="flex w-full items-center gap-3 rounded-lg border border-border bg-card p-3 text-left transition-colors hover:bg-muted focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
                      >
                        <div className="min-w-0 flex-1">
                          <div className="flex flex-wrap items-center gap-2">
                            <span className="font-semibold">{duty.no}</span>
                            <Badge variant="outline">行路 {duty.route}</Badge>
                            <Badge variant={STATUS_BADGE[duty.status]}>
                              {DUTY_STATUS_LABEL[duty.status]}
                            </Badge>
                          </div>
                          {crew ? (
                            <p className="mt-1 truncate text-sm text-muted-foreground">
                              {crew.name}（{duty.kind}）／ {duty.signOn}–
                              {duty.signOff} ／ 拘束 {fmtMinutes(duty.dutyMinutes)}
                              ／ 担当 {duty.trains.join("・")}
                            </p>
                          ) : (
                            <p className="mt-1 text-sm text-destructive">
                              乗務員 未充当 ／ {duty.signOn}–{duty.signOff}
                            </p>
                          )}
                        </div>
                        <IconChevronRight
                          className="size-5 shrink-0 text-muted-foreground"
                          aria-hidden="true"
                        />
                      </button>
                    </li>
                  )
                })}
              </ul>
            </TabsContent>
          </Tabs>

          {/* 予備・欠務 */}
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
            <Card>
              <CardHeader className="p-4 pb-2">
                <CardTitle as="h2" className="flex items-center gap-1.5 text-base">
                  <IconUserCheck className="size-4" aria-hidden="true" />
                  予備（待機）
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-2 p-4 pt-0">
                {SPARE_CREW.map((s) => {
                  const c = CREW_BY_ID[s.id]
                  return (
                    <PersonCell
                      key={s.id}
                      size="sm"
                      name={c?.name ?? s.id}
                      secondary={`${s.id}・${s.role}`}
                      tertiary={"until" in s ? s.until : s.note}
                      trailing={<Badge variant="info">予備</Badge>}
                    />
                  )
                })}
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="p-4 pb-2">
                <CardTitle as="h2" className="flex items-center gap-1.5 text-base">
                  <IconClockPause className="size-4" aria-hidden="true" />
                  年休・病欠
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-2 p-4 pt-0">
                {ABSENCES.map((a) => (
                  <PersonCell
                    key={a.id}
                    size="sm"
                    name={a.name}
                    secondary={`${a.id}・${a.role}`}
                    tertiary={a.note}
                    trailing={
                      <Badge
                        variant={a.kind === "病欠" ? "warning" : "secondary"}
                      >
                        {a.kind}
                      </Badge>
                    }
                  />
                ))}
              </CardContent>
            </Card>
          </div>
        </div>

        {/* 右：要対応アラート */}
        <aside className="min-w-0" aria-labelledby="alerts-heading">
          <div className="lg:sticky lg:top-4">
            <div className="mb-2 flex items-center justify-between">
              <h2 id="alerts-heading" className="text-base font-semibold">
                要対応
              </h2>
              <Badge variant="destructive">
                {ALERTS.filter((a) => a.severity === "critical").length} 重大
              </Badge>
            </div>
            <ActionQueue items={alertItems} emptyLabel="対応が必要な項目はありません" />
            <Separator className="my-4" />
            <p className="text-xs text-muted-foreground">
              重大 → 警告 → 情報 の順。各行を選択すると関係する仕業の詳細（行路・点呼・勤務時間）を開きます。
            </p>
          </div>
        </aside>
      </div>

      <DutyDetail
        duty={selected}
        open={open}
        onOpenChange={setOpen}
        managerId={MANAGER_ID}
      />
    </main>
  )
}

"use client"

import * as React from "react"
import {
  Badge,
  CoSign,
  Drawer,
  DrawerClose,
  DrawerContent,
  DrawerDescription,
  DrawerHeader,
  DrawerTitle,
  Meter,
  MetadataList,
  ReferenceValue,
  RouteStops,
  Separator,
  SignedRecord,
  type CoSignValue,
  type RouteStopItem,
  type SignedRecordValue,
} from "@gunjo/ui"
import {
  IconArrowRight,
  IconClock,
  IconLicense,
  IconShieldCheck,
} from "@tabler/icons-react"

import {
  CREW_BY_ID,
  DUTY_STATUS_LABEL,
  type Duty,
} from "./data"
import { STATUS_BADGE, fmtMinutes, legStatus } from "./helpers"

const LEG_KIND_LABEL: Record<string, string> = {
  depart: "出区",
  train: "列車",
  turn: "折返し",
  rest: "休憩",
  arrive: "入区",
}

function legToStop(duty: Duty): RouteStopItem[] {
  return duty.legs.map((leg, i) => {
    const status = legStatus(leg, duty)
    const titleParts = [LEG_KIND_LABEL[leg.kind]]
    if (leg.trainNo) titleParts.push(leg.trainNo)
    return {
      id: leg.id,
      seq: i + 1,
      status,
      title: (
        <span className="flex flex-wrap items-center gap-1.5">
          <Badge variant={leg.kind === "train" ? "info" : "outline"}>
            {LEG_KIND_LABEL[leg.kind]}
            {leg.trainNo ? ` ${leg.trainNo}` : ""}
          </Badge>
          <span className="font-medium">{leg.label}</span>
        </span>
      ),
      description: leg.note ? leg.note : undefined,
      plannedTime: leg.plannedDep,
      actualTime: leg.actualDep,
      meta: leg.plannedArr ? (
        <span className="inline-flex items-center gap-0.5 text-xs text-muted-foreground">
          着 {leg.plannedArr}
        </span>
      ) : undefined,
    }
  })
}

export function DutyDetail({
  duty,
  open,
  onOpenChange,
  managerId,
}: {
  duty: Duty | null
  open: boolean
  onOpenChange: (open: boolean) => void
  managerId: string
}) {
  // 終了点呼の署名状態（このセッション内で操作可能）
  const [endRecord, setEndRecord] = React.useState<SignedRecordValue>({
    status: "draft",
    addenda: [],
  })
  // 行路変更の 2人確認
  const [coSign, setCoSign] = React.useState<CoSignValue | undefined>(undefined)

  // 仕業が変わったら点呼の下書き状態をリセット
  React.useEffect(() => {
    if (duty?.endRollCall?.signed) {
      setEndRecord({
        status: "signed",
        signedBy: duty.endRollCall.officer,
        signedAt: duty.endRollCall.signedAt ?? undefined,
        addenda: [],
      })
    } else {
      setEndRecord({ status: "draft", addenda: [] })
    }
    setCoSign(undefined)
  }, [duty])

  if (!duty) return null

  const crew = CREW_BY_ID[duty.crewId]
  const start = duty.startRollCall

  return (
    <Drawer open={open} onOpenChange={onOpenChange} direction="right">
      <DrawerContent
        side="right"
        className="w-full max-w-[560px] sm:w-[560px]"
      >
        <DrawerHeader className="border-b">
          <div className="flex flex-wrap items-center gap-2">
            <DrawerTitle className="text-lg">
              {duty.no}
            </DrawerTitle>
            <Badge variant="outline">行路 {duty.route}</Badge>
            <Badge variant={STATUS_BADGE[duty.status]}>
              {DUTY_STATUS_LABEL[duty.status]}
            </Badge>
          </div>
          <DrawerDescription>
            {crew ? `${crew.name}（${crew.id}・${duty.kind}）` : "乗務員 未充当"}
            ／ 出勤 {duty.signOn} – 退勤 {duty.signOff}
          </DrawerDescription>
        </DrawerHeader>

        <div className="flex-1 space-y-6 overflow-y-auto p-4">
          {/* 勤務時間・コンプライアンス */}
          <section aria-labelledby="dd-hours">
            <h3
              id="dd-hours"
              className="mb-2 flex items-center gap-1.5 text-sm font-semibold"
            >
              <IconClock className="size-4" aria-hidden="true" />
              勤務時間・コンプライアンス
            </h3>
            <div className="space-y-3 rounded-lg border border-border bg-card p-3">
              <div>
                <div className="mb-1 flex items-center justify-between text-xs">
                  <span className="text-muted-foreground">
                    拘束時間（上限 {fmtMinutes(crew?.dutyLimitMin ?? 780)}）
                  </span>
                  <span className="font-medium tabular-nums">
                    {fmtMinutes(duty.dutyMinutes)}
                  </span>
                </div>
                <Meter
                  value={duty.dutyMinutes}
                  max={crew?.dutyLimitMin ?? 780}
                  label={`${duty.no} 拘束時間`}
                  unit="分"
                  thresholds={{ warning: 0.85, over: 1 }}
                />
              </div>
              <div>
                <div className="mb-1 flex items-center justify-between text-xs">
                  <span className="text-muted-foreground">
                    連続乗務（上限 {fmtMinutes(crew?.continuousLimitMin ?? 240)}）
                  </span>
                  <span className="font-medium tabular-nums">
                    {fmtMinutes(duty.continuousMinutes)}
                  </span>
                </div>
                <Meter
                  value={duty.continuousMinutes}
                  max={crew?.continuousLimitMin ?? 240}
                  label={`${duty.no} 連続乗務`}
                  unit="分"
                  thresholds={{ warning: 0.9, over: 1 }}
                />
              </div>
              <div className="grid grid-cols-2 gap-3 pt-1 text-sm">
                <div>
                  <p className="text-xs text-muted-foreground">実乗務時間</p>
                  <p className="font-medium tabular-nums">
                    {fmtMinutes(duty.driveMinutes)}
                  </p>
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">休憩計</p>
                  <p className="font-medium tabular-nums">
                    {fmtMinutes(duty.restMinutes)}
                  </p>
                </div>
              </div>
            </div>
          </section>

          {/* 資格・限定 */}
          {crew ? (
            <section aria-labelledby="dd-qual">
              <h3
                id="dd-qual"
                className="mb-2 flex items-center gap-1.5 text-sm font-semibold"
              >
                <IconLicense className="size-4" aria-hidden="true" />
                資格・限定
              </h3>
              <MetadataList
                variant="compact"
                items={[
                  {
                    label: "運転免許",
                    value: crew.license ?? "—（車掌）",
                  },
                  { label: "線区限定", value: crew.lineLimits.join("・") },
                  { label: "車種", value: crew.rollingStock.join("・") },
                ]}
              />
            </section>
          ) : null}

          <Separator />

          {/* 行路（行程） */}
          <section aria-labelledby="dd-route">
            <h3
              id="dd-route"
              className="mb-2 flex items-center gap-1.5 text-sm font-semibold"
            >
              <IconArrowRight className="size-4" aria-hidden="true" />
              行路（行程）
            </h3>
            <p className="mb-2 text-xs text-muted-foreground">
              担当列車：{duty.trains.join(" / ")}
            </p>
            <RouteStops
              stops={legToStop(duty)}
              statusLabels={{
                pending: "未通過",
                current: "在線中",
                completed: "通過済",
                delayed: "遅延",
              }}
              timeLabels={{ planned: "予定発", actual: "実績発" }}
            />
          </section>

          <Separator />

          {/* 出勤点呼（確定済・閲覧） */}
          <section aria-labelledby="dd-start-rollcall">
            <h3
              id="dd-start-rollcall"
              className="mb-2 flex items-center gap-1.5 text-sm font-semibold"
            >
              <IconShieldCheck className="size-4" aria-hidden="true" />
              出勤点呼
            </h3>
            {start.signed ? (
              <div className="space-y-3 rounded-lg border border-border bg-card p-3 text-sm">
                <div className="flex flex-wrap items-center justify-between gap-2">
                  <span className="inline-flex items-center gap-2">
                    <span className="text-xs text-muted-foreground">
                      アルコールチェック
                    </span>
                    {start.alcohol != null ? (
                      <ReferenceValue
                        value={start.alcohol}
                        range={{ high: 0, criticalHigh: 0.15 }}
                        unit="mg/L"
                        showLabel
                        labels={{
                          normal: "検出なし",
                          high: "検出",
                          "critical-high": "基準超過",
                        }}
                      />
                    ) : (
                      <Badge variant="destructive">未実施</Badge>
                    )}
                  </span>
                  <Badge variant="success">確定済</Badge>
                </div>
                <MetadataList
                  variant="compact"
                  items={[
                    { label: "健康状態", value: start.health || "—" },
                    {
                      label: "携行品",
                      value: start.carried.length
                        ? start.carried.join("・")
                        : "—",
                    },
                    { label: "指示事項", value: start.instructions || "—" },
                    { label: "点呼執行者", value: start.officer || "—" },
                  ]}
                />
              </div>
            ) : (
              <div className="rounded-lg border border-dashed border-destructive-border bg-destructive-subtle p-3 text-sm">
                <Badge variant="destructive">点呼未了</Badge>
                <p className="mt-2 text-muted-foreground">
                  出勤点呼・アルコールチェックが未実施です。乗務開始前に執行してください。
                </p>
              </div>
            )}
          </section>

          {/* 終了点呼（署名・確定でロック） */}
          {duty.status === "done" || duty.status === "on-board" ? (
            <section aria-labelledby="dd-end-rollcall">
              <h3
                id="dd-end-rollcall"
                className="mb-2 flex items-center gap-1.5 text-sm font-semibold"
              >
                <IconShieldCheck className="size-4" aria-hidden="true" />
                終了点呼（署名でロック）
              </h3>
              <div className="rounded-lg border border-border bg-card p-3">
                <SignedRecord
                  value={endRecord}
                  onChange={setEndRecord}
                  signerId={managerId}
                  labels={{
                    draft: "下書き",
                    signed: "署名・確定済",
                    sign: "終了点呼を署名・確定",
                    locked:
                      "確定済みの点呼記録は変更できません。修正は追記で行います。",
                    addendaTitle: "追記（事後）",
                  }}
                >
                  {({ readOnly }) => (
                    <div className="space-y-2 text-sm">
                      <MetadataList
                        variant="compact"
                        items={[
                          {
                            label: "終了アルコール",
                            value:
                              duty.endRollCall?.alcohol != null
                                ? `${duty.endRollCall.alcohol.toFixed(2)} mg/L（検出なし）`
                                : "未測定",
                          },
                          {
                            label: "健康状態",
                            value: duty.endRollCall?.health || "良好",
                          },
                          {
                            label: "引継事項",
                            value:
                              duty.endRollCall?.instructions ||
                              "異常なし。引継事項なし。",
                          },
                          {
                            label: "点呼執行者",
                            value: readOnly
                              ? duty.endRollCall?.officer || managerId
                              : `${managerId}（あなた）`,
                          },
                        ]}
                      />
                    </div>
                  )}
                </SignedRecord>
              </div>
            </section>
          ) : null}

          {/* 行路変更の 2人確認（行路支障時） */}
          {duty.status === "turn-back" || duty.status === "roll-call-pending" ? (
            <section aria-labelledby="dd-cosign">
              <h3
                id="dd-cosign"
                className="mb-2 flex items-center gap-1.5 text-sm font-semibold"
              >
                <IconShieldCheck className="size-4" aria-hidden="true" />
                行路変更・交代の 2人確認
              </h3>
              <div className="rounded-lg border border-border bg-card p-3">
                <CoSign
                  primaryId={managerId}
                  value={coSign}
                  onSign={setCoSign}
                  requireReason
                  attestations={[
                    { id: "att-lic", label: "交代要員の免許・線区限定・車種を確認した" },
                    { id: "att-hours", label: "拘束時間・連続乗務が上限内であることを確認した" },
                    { id: "att-rollcall", label: "交代要員の出勤点呼が完了している" },
                  ]}
                  signerLabel="確認者ID（当直 助役 など 2人目）"
                  reasonLabel="変更理由（行路支障 / 連続乗務超過 など）"
                />
              </div>
            </section>
          ) : null}
        </div>

        <DrawerHeader className="border-t">
          <DrawerClose asChild>
            <button
              type="button"
              className="inline-flex h-9 items-center justify-center rounded-lg border border-border px-4 text-sm font-medium hover:bg-muted"
            >
              閉じる
            </button>
          </DrawerClose>
        </DrawerHeader>
      </DrawerContent>
    </Drawer>
  )
}

import type { BadgeProps } from "@gunjo/ui"
import { type Duty, type DutyStatus, type RouteLeg, CREW_BY_ID } from "./data"

type BadgeVariant = NonNullable<BadgeProps["variant"]>

/** 状態 → Badge variant（色だけに頼らずラベルも併記する） */
export const STATUS_BADGE: Record<DutyStatus, BadgeVariant> = {
  before: "outline",
  "roll-called": "info",
  "on-board": "success",
  rest: "secondary",
  "turn-back": "warning",
  done: "secondary",
  "roll-call-pending": "destructive",
}

export function fmtMinutes(min: number): string {
  const h = Math.floor(min / 60)
  const m = min % 60
  return `${h}:${String(m).padStart(2, "0")}`
}

/** RouteLeg → RouteStops の status へマップ。実績の有無で current/completed を推定。 */
export function legStatus(
  leg: RouteLeg,
  duty: Duty,
): "pending" | "current" | "completed" | "delayed" {
  const hasActual = Boolean(leg.actualArr || leg.actualDep)
  const delayed = Boolean(leg.note && leg.note.includes("+"))
  if (duty.status === "done") return "completed"
  if (hasActual) return delayed ? "delayed" : "completed"
  // 折返し待ち / 乗務中の現在地は最初の未実績レグ
  return "pending"
}

export function crewName(crewId: string): string {
  return CREW_BY_ID[crewId]?.name ?? "未充当"
}
